var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>그라운드 원</color> 관리국 본부","JPN":"管理局直轄都市<color=#ffd34c>グラウンド・ワン</color>、管理局本部","ENG":"Administration Direct Control City, <color=#ffd34c>Ground One</color> Administration HQ","TWN":"管理局直轄城市<color=#ffd34c>G1</color>管理局本部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어 님……?","JPN":"シニア様……？","ENG":"Ma'am...?","TWN":"Senior……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L5_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"샤레이드의 선로전환기가… 폭발했습니다…….","JPN":"シャレードの線路転換器が……爆発しました……","ENG":"The Track Switcher in Charade... It exploded...","TWN":"查雷德的線路轉換器……爆炸了……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐라고!? 그게 무슨 헛소리야!?","JPN":"何だと！？　どういうことだ！？","ENG":"What?! What kind of nonsense is that?!","TWN":"什麼！？你在胡說八道什麼！？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"외부 변수는? 전환기에 과부하라도 걸린 거야? 그것도 아니라면…….","JPN":"外部の変数は？　転換器に過負荷がかかったのか？　それとも……","ENG":"Were there any external variables? Did the Switcher overload? Or was it something else...?","TWN":"外部變數呢？轉換器過載了嗎？還是……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"아니요. 모든 동작은 완전히 정상이었어요.","JPN":"いいえ、作動手順にはまったく問題がありませんでした。","ENG":"No. All systems were functioning perfectly normally.","TWN":"不，所有運作都正常。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"원인불명… 장치를 가동하는 순간, 임계치에서 갑자기 폭발했습니다…….","JPN":"原因不明……装置を稼働した瞬間、臨界値で突然爆発しました……","ENG":"Cause unknown... The moment the device was activated, it suddenly exploded at the critical point...","TWN":"原因不明……在裝置啟動的瞬間，在臨界值突然發生爆炸……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"원인불명…? 지금 장난해……!?","JPN":"原因不明だと……？　ふざけるな……！","ENG":"Unknown cause...? Are you kidding me right now...?!","TWN":"原因不明……？你在開玩笑嗎……！？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드에 있는 모두가 목숨을 걸고 있다고! 원인불명이라는 말이……","JPN":"シャレードにいる全員が命をかけているんだぞ！　原因不明だなんて……","ENG":"Everyone in Charade is risking their lives! \\"Unknown cause\\" is not–","TWN":"查雷德那邊的所有人都賭上了性命啊！原因不明這種話……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"잠깐!?","JPN":"待てよ！？","ENG":"Wait?!","TWN":"等等！？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"선로전환기는 엄청난 양의 이터니움을 동력원으로 사용하고 있어…….","JPN":"線路転換器は凄まじい量のエタニウムを動力源にしている……","ENG":"The Track Switcher uses an enormous amount of Eternium as its power source...","TWN":"線路轉換器是以極大量的永恆之金作為動力源……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"현장에 있던 사람들은!? 그게 폭발해 버리면, 아무리 카운터라도 무사하지 못한다고!!","JPN":"現場にいた人たちは！？　あれが爆発したら、カウンターといえど無事では済まないはずだ！！","ENG":"What about the people on site?! If that thing exploded, not even a Counter would survive!!","TWN":"現場的人呢！？那種東西一旦爆炸，就算是制裁者也不可能毫髮無傷！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그게……. ","JPN":"それが…… ","ENG":"That's...","TWN":"那個…… "},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시그널 로스트. 현재, 모든 작전 요원 연락 두절입니다.","JPN":"シグナルロスト。現在、全エージェントと連絡がとれません。","ENG":"Signal lost. All active operatives are currently unreachable.","TWN":"訊號喪失，目前所有作戰人員皆無法取得聯絡。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"도대체가……!","JPN":"いったい……！","ENG":"What...?!","TWN":"到底是怎麼回事……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"도대체 샤레이드에서 지금 무슨 일이 일어나고 있는 거야……!!","JPN":"いったいシャレードで何が起きているんだ……！！","ENG":"What on earth is happening in Charade right now...!!","TWN":"查雷德現在到底發生了什麼事啊……！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 대균열 영향권\\n<color=#ffd34c>DL-6</color> 선로전환기 배치 지점","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>大亀裂影響圏内\\n<color=#ffd34c>DL-6</color>線路転換器配置地点","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Grand Dimension Crevice\\n<color=#ffd34c>DL-6</color> Track Switcher Deployment Site","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>大峽谷影響範圍\\n<color=#ffd34c>DL-6</color>線路轉換器設置地點"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"으윽… 갑자기 폭발이라니…….","JPN":"うっ……いきなり爆発だなんて……","ENG":"Ugh... That explosion came out of nowhere...","TWN":"唔……竟然突然爆炸……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 살아 있어요……?","JPN":"ライカ、生きてる……？","ENG":"Laika, are you alive...?","TWN":"萊卡，你還活著嗎……？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"큭, 더럽게 아프지만, 어찌저찌 살아는 있어.","JPN":"くっ、めちゃくちゃ痛いけどなんとか生きてるよ。","ENG":"Kgh, it hurts like hell, but I'm somehow still alive.","TWN":"嘖，我快痛死了，但總算撐過來了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이 녀석이 아니었으면, 아마도 둘 다 폭발에 휘말려 버렸겠지.","JPN":"こいつがいなかったら、仲良く爆発に巻き込まれただろうな。","ENG":"If it weren't for this thing, we'd probably both have been caught in the blast.","TWN":"要不是這傢伙，恐怕我們兩個都會被捲入爆炸吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이 녀석이라니……?","JPN":"こいつ……？","ENG":"This thing...?","TWN":"這傢伙……？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"하하! 다행일세! 이 몸의 아다만트 합금 장갑이 폭발을 막아낸 모양이군!","JPN":"はは！　よかったな！　吾輩のアダマント合金装甲が爆発を防げたようだ！","ENG":"Haha! What a relief! Looks like my adamant alloy armor blocked the explosion!","TWN":"哈哈！太好了！看來是我這身亞達曼合金裝甲擋下了爆炸呢！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH_04"},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"히, 히페리온……? 당신 몸이……?","JPN":"は、ハイペリオン……？　あなた体が……？","ENG":"H-Hyperion...? Your body...?","TWN":"海、海柏利昂……？你的身體……？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"물론, 히페리온 모듈 아머가 파괴됐다는 사소한 문제가 있지만 말이야!","JPN":"もちろん、ハイペリオンモジュールアーマーが破壊されたという些細な問題はあるがな！","ENG":"Well, there's the minor issue that the Hyperion module armor was destroyed!","TWN":"當然，海柏利昂模組裝甲壞了這點，有點小麻煩就是了！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"반중력 비행은 불가능하겠지만, 자네들을 구해냈으니 어떠한가!","JPN":"反重力飛行は不可能になったが、何とか君たちを助けられたのだ！　これぐらいどうってこともない！","ENG":"I can't use anti-gravity flight anymore, but I saved you, didn't I?!","TWN":"反重力飛行是辦不到了，不過能救了你們也很讚啊！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"고마워요, 히페리온!","JPN":"ありがとうございます、ハイペリオン！","ENG":"Thank you, Hyperion!","TWN":"謝謝你，海柏利昂！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"대체 무슨 일이 일어난 거야? 이 폭발은 뭔데?","JPN":"いったい何が起きたんだ？　さっきの爆発は？","ENG":"What just happened? What was that explosion?","TWN":"到底發生什麼事？這爆炸又是怎麼回事？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"다른 사람들은 어떻게 됐지? 이 정도 폭발에 휘말린다면…….","JPN":"他の人たちは？　これほどの爆発に巻き込まれたなら……","ENG":"What about the others? If they were caught in a blast like that–","TWN":"其他人怎麼樣了？要是被捲入這種規模的爆炸……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 아무래도 작전은 실패한 것 같아요.","JPN":"ライカ、どうやら作戦は失敗したみたい。","ENG":"Laika, I think the operation has failed.","TWN":"萊卡，看來作戰失敗了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"저길 봐요, 대균열로부터 무언가 이쪽을 바라보고 있어요…….","JPN":"あれを見て。大亀裂から何かがこっちを見つめているわ……","ENG":"Look over there. Something's staring at us from the Grand Dimension Crevice...","TWN":"你看那邊，有什麼正從大峽谷那頭看著我們……"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"저게 다른 도시를 뒤덮었던 뿌리인가……?","JPN":"あれが他の都市を覆ったという根……？","ENG":"Are those the roots that swallowed other cities...?","TWN":"那就是覆蓋其他城市的根嗎……？"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"제길, 질척질척해서 완전 기분 나쁘게 생겼잖아?","JPN":"べたべたして気持ち悪そう！","ENG":"Damn it, it's all sticky-looking and disgusting.","TWN":"可惡，又黏又噁心，長得就讓人不舒服！"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"샤레이드 방어는 실패예요.","JPN":"シャレードの防衛は失敗よ。","ENG":"Charade's defense has failed.","TWN":"查雷德的防衛已經失敗了。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이제 우리가 할 수 있는 건, 최대한 많은 사람을 구해내는 거겠죠.","JPN":"今の私たちにできるのは、少しでも多くの人を救い出すことだけ。","ENG":"All we can do now is save as many people as possible.","TWN":"現在我們能做的，就只有盡可能多救一些人吧。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러기 위해서는…….","JPN":"そのためには……","ENG":"To do that...","TWN":"為了做到這點……"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"흠~ 흠흠. 하나에서 여럿으로 여럿에서 하나로~","JPN":"ふん〜ふんふん。一つから多数に。多数から一つに～","ENG":"*Humming* From one to all. From all to one.","TWN":"哼～哼哼。從一變多，從多變一～"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"들리나요, 레지나? 이 세계가 고통에 잠기는 소리가, 생명이 하나둘씩 꺼져가는 소리가.","JPN":"聞こえますか、レジーナ？　この世界が苦痛に沈む音が。命の光が一つ一つ消えていく音が。","ENG":"Can you hear it, Regina? The sound of this world drowning in pain, the sound of lives being extinguished one by one.","TWN":"聽得見嗎，蕾佳娜？這個世界陷入痛苦的聲音，生命一個個消逝的聲音。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"세계가 멸망하기 직전에 들려오는 단말마는 언제 들어도 참 각별해요.","JPN":"滅びを前にした世界が聞かせてくれる断末魔は、いつ聞いても格別なものですね。","ENG":"The death throes heard just before a world ends are always so exquisite.","TWN":"世界即將毀滅前傳來的哀號，無論聽幾次都讓人陶醉。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그리고 레지나도 참 대단하네요.","JPN":"それに、レジーナも大したものですね。","ENG":"And Regina, you really are remarkable.","TWN":"而且，蕾佳娜你也真是了不起。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"선로전환기가 폭발하는 순간, 어머니께 자신이 아닌 타인을 구할 것을 강제하다니…….","JPN":"線路転換器が爆発する瞬間、お母さんに自分ではなく他人を助けるように強制するとは……","ENG":"Forcing Mother to save others instead of herself at the moment the Track Switcher exploded...","TWN":"在線路轉換器爆炸的瞬間，竟然強迫母親拯救他人而不是你自己……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"동결된 시간 속, 찰나의 순간일 뿐이지만, 비로소 저희 단 둘만이 남았네요.","JPN":"凍結した時間の中、刹那にすぎませんがやっと二人きりになれましたね。","ENG":"In frozen time, only a fleeting instant, but at last it is just the two of us.","TWN":"雖然只是凍結時間中的一瞬間，但現在終於只剩下我們兩個了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"자, 이제 뭐하고 놀까요, 레지나?","JPN":"さあ、レジーナ。何をして遊びましょうか？","ENG":"So, how shall we play now, Regina?","TWN":"來吧，蕾佳娜。接下來要玩什麼呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_15"},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"당신의 그 손가락을 비튼다면, 어머니가 어떤 표정을 지을까요?","JPN":"あなたのその指を捻ったら、お母さんはどんな顔をするでしょうか？","ENG":"If I twist those fingers of yours, what kind of face will Mother make?","TWN":"如果我把你的手指一根根扭斷，母親會露出什麼表情呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"절 응시하는 그 눈알을 파낸다면, 어머니가 어떻게 꾸짖을까요?","JPN":"私を見つめるその目玉をえぐり出したら、お母さんはどう叱るのでしょうか？","ENG":"If I gouge out those eyes staring at me, how will Mother scold me?","TWN":"如果我把那雙直視著我的眼球挖出來，母親又會怎麼斥責我呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"만일, 제가 당신을 <color=#ff3636>미식</color>하기라도 한다면, 어머니는 저를 <color=#ff3636>탐식</color>하기 위해, 예전처럼 수단과 방법을 가리지 않겠죠?","JPN":"もし、私があなたを<color=#ff3636>美食</color>でもしたら、お母さんは私を<color=#ff3636>貪食</color>するために、昔みたいに手段を選ばなくなるでしょうね。","ENG":"And if I were to <color=#ff3636>taste</color> you, then Mother would once again stop at nothing to <color=#ff3636>devour</color> on me, wouldn't she?","TWN":"要是我乾脆<color=#ff3636>品嘗</color>你，母親一定會像以前那樣，不擇手段地想要<color=#ff3636>吞噬</color>我吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그렇다면, 우리 지식의 호수는 비로소 다시 하나가 될 거예요……!","JPN":"そうしたら、我々知識の湖はようやく、また一つになります……！","ENG":"Then our Lake of Knowledge would finally become one again...!","TWN":"那樣一來，我們知識湖水就能重新合而為一了……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……에델은 응석받이를 키웠군요.","JPN":"……エデルは甘えん坊を育てましたわね。","ENG":"...Edel certainly raised a spoiled child.","TWN":"……艾瑟兒真是養出了一個被寵壞的孩子。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"하지만 모든 지식의 호수는 오직 종신학회장인 저만의 것.","JPN":"ですがすべての知識の湖は、終身学会長である私のもの。","ENG":"But every Lake of Knowledge belongs solely to me, the Tenured President.","TWN":"但所有知識湖水只屬於身為終身學會長的我。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그건 당신도 예외가 아니랍니다, 방해자.","JPN":"あなたも例外ではありませんわ、邪魔者。","ENG":"You are no exception, Disturber.","TWN":"你也不例外，妨礙者。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아하하! 당신은 정말로 애증의 존재예요, 레지나!","JPN":"あはは！　あなたは本当に愛憎の存在です、レジーナ！","ENG":"Ahahaha! You really are a being of love and hate, Regina!","TWN":"啊哈哈！你真是讓人又愛又恨的存在呢，蕾佳娜！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"당신이 정말 싫은데! 당신이 너무 사랑스러워서 제 자신을 주체할 수가 없어요!","JPN":"あなたが大嫌いなのに！　あなたが愛しすぎて我慢できない！","ENG":"I hate you so much! And yet you are so lovely I cannot contain myself!","TWN":"我真的很討厭你！卻又因為你太可愛，讓我無法控制自己！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그러니까 레지나, 당신을 맛봐도 괜찮을까요……?","JPN":"だからレジーナ、あなたを味わってもいいですか……？","ENG":"So Regina, may I have a taste of you...?","TWN":"所以啊，蕾佳娜……我可以嚐嚐你的味道嗎……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"방해자!! 나의 레지나 님께 무례를 범하다니……!!","JPN":"邪魔者！！　我々のレジーナ様に無礼を働くなんて……！！","ENG":"Disturber!! How dare you insult our Regina...!!","TWN":"妨礙者！！竟敢對我的蕾佳娜大人如此無禮……！！"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_42"},{"id":"L47_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"이런, 어머니께 밀회를 들켜버렸네요! 레지나를 맛볼 기회였는데……!","JPN":"あら、お母さんに逢瀬を見られてしまいましたね！　せっかくレジーナを味わうチャンスだったのに……！","ENG":"Oh dear, Mother caught us in a tryst! It was my chance to taste Regina...!","TWN":"哎呀，被母親撞見幽會了呢！明明就差一點可以品嘗蕾佳娜了……！"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"방해자…….","JPN":"邪魔者……","ENG":"Disturber...","TWN":"妨礙者……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아무래도 그 건방진 입부터 갈갈이 찢어 버려야겠군요……!","JPN":"その生意気な口から引き裂いてやらねばなりませんね……！","ENG":"It seems I will have to tear that insolent mouth apart first...!","TWN":"看來得先撕爛你那張狂妄的嘴才行呢……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"후후, 어머니도 참~ 저는 입이 많아서 제법 시간이 걸릴걸요?","JPN":"ふふ、お母さんったらもう～。私、口がたくさんあるから結構かかりますよ？","ENG":"Fufu. Oh, Mother. I have many mouths, so that might take a while.","TWN":"呵呵，母親也真是的～我有很多嘴巴，要花不少時間喔？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_14"},{"id":"L6_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그리고…….","JPN":"それに……","ENG":"And besides...","TWN":"而且……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"지금은 제가 레지나랑 이야기 중이잖아요, 어머니?","JPN":"今は私とレジーナがお話し中ですよ？　お母さん。","ENG":"I am in the middle of a conversation with Regina right now, Mother.","TWN":"現在我在跟蕾佳娜說話呢，母親？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"큭, 또 봉인 사슬이……!","JPN":"くっ、また封印の鎖が……！","ENG":"Tch, the Sealing Chains again...!","TWN":"嘖，又是封印鎖鏈……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ONLY_FIERCE_ESPR_KNIGHT_PASSIVE_2"},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"동결되었던 시간이 움직이기 시작한다면…….","JPN":"凍結された時間が動き出したら……","ENG":"When frozen time begins to move once more...","TWN":"等凍結的時間再次流動……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈과 대적하는 것은 또다시 내가 되겠지, 에델 마이트너.","JPN":"俺が再度、貴様を相手することが筋なのだろう、エデル・マイトナー。","ENG":"It will be me who stands against you again, Edel Meitner.","TWN":"再次與你對峙的又會是我吧，艾瑟兒．邁特納。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"전과 다른 점이 있다면, 이번에는 네놈들이 지키는 쪽이라는 것이다.","JPN":"以前と違う点があるとすれば、今度は貴様らが守る側だということだ。","ENG":"If there is one difference from before, it is that this time, you are the ones defending.","TWN":"若說和之前有什麼不同，那就是這次是你們在防守方。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"호수의 기사……!","JPN":"湖の騎士……！","ENG":"Knight of the Lake...!","TWN":"湖水騎士……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 세계에서도 또다시 저희와 대적할 생각인가요, 버넷?","JPN":"この世界でもまた我々に仇なすつもりですか？　バーネット。","ENG":"Do you intend to oppose us again in this world as well, Burnett?","TWN":"在這個世界也打算再次與我們為敵嗎，伯內特？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"과거, 충의를 저버린 당신이 정말 저희의 상대가 될 수 있을 거라고 생각하시나요?","JPN":"過去、忠義を捨てたあなたが本当に我々の相手になれるとでも？","ENG":"Do you truly believe you can stand against us, after betraying your loyalty in the past?","TWN":"你真的認為曾經背棄忠義的你，還有資格成為我們的對手嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"충의라, 재미있군.","JPN":"忠義か、面白い。","ENG":"Loyalty, you say. How amusing.","TWN":"忠義啊，真有意思。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"지식의 호수는 하나가 되어야 한다.","JPN":"知識の湖は一つにならねばならない。","ENG":"The Lake of Knowledge must become one.","TWN":"知識湖水必須化為一體。"},"stage":{"bg":"OMEN_CHARADE_03","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_KNIGHT_IN_TRAILER_11"},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그것이 지금 제가 바쳐야 할 충의의 맹세라면.","JPN":"それが今俺が捧げるべき忠義の誓いであるのなら。","ENG":"If that is the vow of loyalty I must now offer.","TWN":"若那是我現在必須獻上的忠義誓言，"},"stage":{"bg":"OMEN_CHARADE_03","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_KNIGHT_IN_TRAILER_12"},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"기꺼이 받아들이겠습니다.","JPN":"よろこんで受け入れます。","ENG":"I will accept it without hesitation.","TWN":"我欣然接受。"},"stage":{"bg":"OMEN_CHARADE_03","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_KNIGHT_IN_TRAILER_13"},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"……나의 어머니시여.","JPN":"お母さん。","ENG":"...My Mother.","TWN":"我的母親。"},"stage":{"bg":"OMEN_CHARADE_04","bgm":"THEMA_CA_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_KNIGHT_IN_TRAILER_14"}]`);export{e as default};